set-variable.value:
@{
    try   { return context.Request.Body.As<JObject>(preserveContent: true); }
    catch { return null; }
  }

@{
    try {
      var map  = JObject.Parse((string)context.Variables["agentMapNamedValue"]);
      var name = (string)context.Variables["agentName"];
      if (map[name] == null) { return null; }
      return map[name].ToString();
    }
    catch { return null; }
  }

return-response.set-body:
@{
          return new JObject(
            new JProperty("error",   "agent_not_found"),
            new JProperty("field",   "agentName"),
            new JProperty("message", $"Agent '{(string)context.Variables["agentName"]}' was not found in the agent map. Check agentName or update the Named Value.")
          ).ToString();
        }

@{
          var status = ((IResponse)context.Variables["threadResp"]).StatusCode;
          var msg = (status == 401 || status == 403)
            ? "Your identity does not have permission to access this Azure AI Foundry project. Verify your RBAC role on the Foundry resource."
            : $"Failed to create a conversation thread on Azure AI Foundry (HTTP {status}). Please retry or contact support.";
          return new JObject(
            new JProperty("error",         "thread_creation_failed"),
            new JProperty("foundryStatus", status),
            new JProperty("message",       msg)
          ).ToString();
        }

send-request.set-body:
@{
      return new JObject(
        new JProperty("role",    "user"),
        new JProperty("content", (string)context.Variables["userMessage"])
      ).ToString();
    }

return-response.set-body:
@{
          var status = ((IResponse)context.Variables["msgResp"]).StatusCode;
          return new JObject(
            new JProperty("error",         "message_post_failed"),
            new JProperty("threadId",      (string)context.Variables["threadId"]),
            new JProperty("foundryStatus", status),
            new JProperty("message",       $"Failed to post message to thread (HTTP {status}).")
          ).ToString();
        }

@{
          var status = ((IResponse)context.Variables["runResp"]).StatusCode;
          return new JObject(
            new JProperty("error",         "run_creation_failed"),
            new JProperty("threadId",      (string)context.Variables["threadId"]),
            new JProperty("assistantId",   (string)context.Variables["assistantId"]),
            new JProperty("foundryStatus", status),
            new JProperty("message",       $"Failed to start the agent run (HTTP {status}). Verify the agentName maps to a valid deployed assistant.")
          ).ToString();
        }

@{
          return new JObject(
            new JProperty("error",    "agent_run_failed"),
            new JProperty("runId",    (string)context.Variables["runId"]),
            new JProperty("threadId", (string)context.Variables["threadId"]),
            new JProperty("message",  "The agent run failed. Please retry or contact support with the runId.")
          ).ToString();
        }

@{
          return new JObject(
            new JProperty("error",    "agent_run_cancelled"),
            new JProperty("runId",    (string)context.Variables["runId"]),
            new JProperty("threadId", (string)context.Variables["threadId"]),
            new JProperty("message",  "The agent run was cancelled. Please retry.")
          ).ToString();
        }

@{
          return new JObject(
            new JProperty("error",    "agent_run_expired"),
            new JProperty("runId",    (string)context.Variables["runId"]),
            new JProperty("threadId", (string)context.Variables["threadId"]),
            new JProperty("message",  "The agent run expired. Simplify your message or retry.")
          ).ToString();
        }

@{
          return new JObject(
            new JProperty("error",    "requires_action"),
            new JProperty("runId",    (string)context.Variables["runId"]),
            new JProperty("threadId", (string)context.Variables["threadId"]),
            new JProperty("message",  "The agent requires a tool call response. Submit the tool output to resume.")
          ).ToString();
        }

@{
          return new JObject(
            new JProperty("status",   (string)context.Variables["runStatus"]),
            new JProperty("runId",    (string)context.Variables["runId"]),
            new JProperty("threadId", (string)context.Variables["threadId"]),
            new JProperty("message",  "Agent still processing. Use runId and threadId to poll.")
          ).ToString();
        }
